{% extends "base.html" %}

{% block title %}Dashboard - Maimai Assistant{% endblock %}

{% block content %}
<h2>Dashboard</h2>

<div class="grid">
    <article>
        <header>Connection Status</header>
        <p>Browser: <strong id="browser-status">--</strong></p>
        <p>Login: <strong id="login-status">--</strong></p>
        <p>CDP: <code id="cdp-endpoint">--</code></p>
        <footer>
            <button class="outline" onclick="checkStatus()">Refresh</button>
        </footer>
    </article>

    <article>
        <header>Task Queue</header>
        <p>Queue size: <strong id="queue-size">0</strong></p>
        <p>Current task: <strong id="current-task">None</strong></p>
        <footer>
            <a href="/search" role="button" class="outline">New Search</a>
            <a href="/pipeline" role="button">New Pipeline</a>
        </footer>
    </article>
</div>

<h3>Recent Tasks</h3>
<table id="recent-tasks">
    <thead>
        <tr>
            <th>ID</th>
            <th>Name</th>
            <th>Status</th>
            <th>Created</th>
        </tr>
    </thead>
    <tbody>
        <tr><td colspan="4">Loading...</td></tr>
    </tbody>
</table>
{% endblock %}

{% block scripts %}
<script>
async function checkStatus() {
    try {
        const [authRes, statusRes, tasksRes] = await Promise.all([
            fetch('/api/auth/status'),
            fetch('/api/status'),
            fetch('/api/tasks?limit=10'),
        ]);
        const auth = await authRes.json();
        const status = await statusRes.json();
        const tasks = await tasksRes.json();

        document.getElementById('browser-status').textContent = auth.browser_connected ? 'Connected' : 'Disconnected';
        document.getElementById('browser-status').style.color = auth.browser_connected ? 'var(--pico-color-green-500)' : 'var(--pico-color-red-500)';
        document.getElementById('login-status').textContent = auth.logged_in ? 'Logged in' : 'Not logged in';
        document.getElementById('login-status').style.color = auth.logged_in ? 'var(--pico-color-green-500)' : 'var(--pico-color-red-500)';
        document.getElementById('cdp-endpoint').textContent = auth.cdp_endpoint;

        document.getElementById('queue-size').textContent = status.queue.queue_size;
        document.getElementById('current-task').textContent = status.queue.current_task ? status.queue.current_task.name : 'None';

        // Update connection badge
        const badge = document.getElementById('connection-badge');
        if (auth.browser_connected && auth.logged_in) {
            badge.textContent = 'Online';
            badge.dataset.status = 'ok';
        } else if (auth.browser_connected) {
            badge.textContent = 'Not Logged In';
            badge.dataset.status = 'warn';
        } else {
            badge.textContent = 'Offline';
            badge.dataset.status = 'error';
        }

        // Recent tasks
        const tbody = document.querySelector('#recent-tasks tbody');
        if (tasks.length === 0) {
            tbody.innerHTML = '<tr><td colspan="4">No tasks yet</td></tr>';
        } else {
            tbody.innerHTML = tasks.map(t => `
                <tr>
                    <td><code>${t.task_id}</code></td>
                    <td>${t.name}</td>
                    <td><span class="badge" data-status="${t.status}">${t.status}</span></td>
                    <td>${new Date(t.created_at).toLocaleString()}</td>
                </tr>
            `).join('');
        }
    } catch (e) {
        console.error('Status check failed:', e);
    }
}

checkStatus();
setInterval(checkStatus, 10000);
</script>
{% endblock %}

{% extends "base.html" %}

{% block title %}Pipeline - Maimai Assistant{% endblock %}

{% block content %}
<h2>Pipeline (Search + Message)</h2>

<form id="pipeline-form">
    <div class="grid">
        <label>
            Keywords (one per line)
            <textarea name="keywords" rows="3" placeholder="e.g. 前端工程师" required></textarea>
        </label>
        <label>
            Company filter (one per line, optional)
            <textarea name="company" rows="3" placeholder="e.g. 字节跳动"></textarea>
        </label>
    </div>
    <div class="grid">
        <label>
            Template
            <select name="template" id="template-select" required>
                <option value="">Loading...</option>
            </select>
        </label>
        <label>
            Pages
            <input type="number" name="pages" value="1" min="1" max="50">
        </label>
    </div>
    <div id="template-vars"></div>
    <fieldset>
        <label>
            <input type="checkbox" name="auto_send">
            Auto-send (skip candidate confirmation)
        </label>
        <label>
            <input type="checkbox" name="dry_run">
            Dry run (search only, no messages)
        </label>
    </fieldset>
    <button type="submit">Start Pipeline</button>
</form>

<!-- Progress section -->
<div id="pipeline-progress" hidden>
    <article>
        <header>
            <span id="pipeline-status-text">Queued...</span>
            <span id="pipeline-task-id" class="badge" style="float:right"></span>
        </header>
        <progress id="pipeline-progress-bar" value="0" max="100"></progress>
        <p id="pipeline-detail"></p>
    </article>
</div>

<!-- Confirmation section (manual mode) -->
<div id="pipeline-confirm" hidden>
    <article>
        <header>Select Candidates to Message</header>
        <p>
            <label>
                <input type="checkbox" id="select-all" onchange="toggleSelectAll(this.checked)">
                Select All (<span id="confirm-count">0</span> candidates)
            </label>
        </p>
        <div id="candidate-list"></div>
        <footer>
            <button onclick="confirmCandidates()" class="primary">Confirm & Send</button>
            <button onclick="confirmCandidates(true)" class="secondary outline">Cancel</button>
        </footer>
    </article>
</div>

<!-- Results -->
<div id="pipeline-results" hidden>
    <article>
        <header>Pipeline Complete</header>
        <div id="results-summary"></div>
    </article>
</div>
{% endblock %}

{% block scripts %}
<script src="/static/js/pipeline.js"></script>
<script>
// Load templates on page load
(async () => {
    try {
        const res = await fetch('/api/templates');
        const templates = await res.json();
        const select = document.getElementById('template-select');
        select.innerHTML = templates.map(t =>
            `<option value="${t.name}">${t.name} — ${t.description || 'No description'}</option>`
        ).join('');

        // Show template variables when selection changes
        select.addEventListener('change', () => {
            const tpl = templates.find(t => t.name === select.value);
            const varsDiv = document.getElementById('template-vars');
            if (tpl && tpl.variables.length) {
                // Filter out auto-filled variables
                const autoVars = ['name', 'company', 'position'];
                const manualVars = tpl.variables.filter(v => !autoVars.includes(v));
                if (manualVars.length) {
                    varsDiv.innerHTML = '<fieldset><legend>Template Variables</legend>' +
                        manualVars.map(v =>
                            `<label>${v}<input type="text" name="var_${v}" placeholder="${v}"></label>`
                        ).join('') + '</fieldset>';
                } else {
                    varsDiv.innerHTML = '<small>Variables (name, company, position) will be auto-filled per candidate.</small>';
                }
            } else {
                varsDiv.innerHTML = '';
            }
        });
        select.dispatchEvent(new Event('change'));
    } catch (e) {
        console.error('Failed to load templates:', e);
    }
})();
</script>
{% endblock %}

