/**
 * Pipeline page interaction logic.
 * Supports dual mode: search-only (no template) and pipeline (with template).
 */

let pipelineTaskId = null;
let pipelineWS = null;
let pipelineCandidates = [];

document.getElementById('pipeline-form').addEventListener('submit', async (e) => {
    e.preventDefault();
    const form = e.target;

    const keywords = form.keywords.value.split('\n').map(s => s.trim()).filter(Boolean);
    const company = form.company.value.split('\n').map(s => s.trim()).filter(Boolean);
    const location = form.location ? form.location.value.trim() || null : null;
    const template = form.template.value;
    const pages = parseInt(form.pages.value) || 1;

    if (!keywords.length) return alert('Please enter at least one keyword');

    // Hide all result sections
    document.getElementById('pipeline-progress').hidden = false;
    document.getElementById('pipeline-confirm').hidden = true;
    document.getElementById('pipeline-results').hidden = true;
    document.getElementById('search-results').hidden = true;
    form.querySelector('button[type="submit"]').disabled = true;

    const isSearchOnly = !template;

    if (isSearchOnly) {
        // --- Search-only mode ---
        try {
            const res = await fetch('/api/search', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({keywords, company, location, pages}),
            });
            const data = await res.json();
            pipelineTaskId = data.task_id;
            document.getElementById('pipeline-task-id').textContent = data.task_id;
            document.getElementById('pipeline-status-text').textContent = 'Searching...';

            connectTaskWS(data.task_id, {
                onEvent(msg) {
                    document.getElementById('pipeline-status-text').textContent =
                        `${msg.event}: ${msg.keyword || ''} ${msg.found ? '(' + msg.found + ' found)' : ''}`;
                },
                onComplete(msg) {
                    const candidates = msg.result || [];
                    showSearchResults(candidates);
                    document.getElementById('pipeline-progress').hidden = true;
                    form.querySelector('button[type="submit"]').disabled = false;
                },
                onError(msg) {
                    alert('Search failed: ' + (msg.error || 'Unknown error'));
                    document.getElementById('pipeline-progress').hidden = true;
                    form.querySelector('button[type="submit"]').disabled = false;
                },
            });
        } catch (e) {
            alert('Request failed: ' + e.message);
            document.getElementById('pipeline-progress').hidden = true;
            form.querySelector('button[type="submit"]').disabled = false;
        }
    } else {
        // --- Pipeline mode ---
        const auto_send = form.auto_send.checked;

        // Collect template variables
        const variables = {};
        form.querySelectorAll('[name^="var_"]').forEach(input => {
            const key = input.name.replace('var_', '');
            if (input.value.trim()) variables[key] = input.value.trim();
        });

        try {
            const res = await fetch('/api/pipeline', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({keywords, company, template, pages, variables, auto_send}),
            });
            const data = await res.json();
            pipelineTaskId = data.task_id;
            document.getElementById('pipeline-task-id').textContent = data.task_id;

            pipelineWS = connectTaskWS(data.task_id, {
                onEvent(msg) {
                    handlePipelineEvent(msg);
                },
                onComplete(msg) {
                    showPipelineResults(msg.result);
                    document.getElementById('pipeline-progress').hidden = true;
                    form.querySelector('button[type="submit"]').disabled = false;
                },
                onError(msg) {
                    document.getElementById('pipeline-status-text').textContent = 'Failed';
                    document.getElementById('pipeline-detail').textContent = msg.error || 'Unknown error';
                    form.querySelector('button[type="submit"]').disabled = false;
                },
            });

            pollTask(data.task_id, (task) => {
                if (task.status === 'completed') {
                    showPipelineResults(task.result);
                    document.getElementById('pipeline-progress').hidden = true;
                    form.querySelector('button[type="submit"]').disabled = false;
                    if (pipelineWS) pipelineWS.close();
                }
            }, 3000);

        } catch (e) {
            alert('Request failed: ' + e.message);
            form.querySelector('button[type="submit"]').disabled = false;
            document.getElementById('pipeline-progress').hidden = true;
        }
    }
});

function handlePipelineEvent(msg) {
    const statusEl = document.getElementById('pipeline-status-text');
    const detailEl = document.getElementById('pipeline-detail');
    const progressBar = document.getElementById('pipeline-progress-bar');

    switch (msg.event) {
        case 'search_progress':
            statusEl.textContent = `Searching: ${msg.keyword} (${msg.keyword_index}/${msg.total_keywords})`;
            break;

        case 'search_keyword_done':
            detailEl.textContent = `Found ${msg.found} candidates for "${msg.keyword}" (${msg.total_so_far} total)`;
            break;

        case 'search_complete':
            statusEl.textContent = 'Search complete';
            detailEl.textContent = `${msg.candidates.length} candidates found`;
            break;

        case 'awaiting_confirmation':
            statusEl.textContent = 'Awaiting your confirmation';
            document.getElementById('pipeline-progress').hidden = true;
            showConfirmation(msg.candidates);
            break;

        case 'sending_started':
            statusEl.textContent = 'Sending messages...';
            progressBar.max = msg.total;
            progressBar.value = 0;
            document.getElementById('pipeline-progress').hidden = false;
            document.getElementById('pipeline-confirm').hidden = true;
            break;

        case 'send_progress':
            statusEl.textContent = `Sending: ${msg.current} (${msg.sent}/${msg.total})`;
            progressBar.value = msg.sent + msg.failed;
            progressBar.max = msg.total;
            detailEl.textContent = `Sent: ${msg.sent}, Failed: ${msg.failed}`;
            break;

        case 'completed':
            showPipelineResults(msg.result);
            break;

        default:
            detailEl.textContent = JSON.stringify(msg);
    }
}

function showConfirmation(candidates) {
    pipelineCandidates = candidates;
    document.getElementById('pipeline-confirm').hidden = false;
    document.getElementById('confirm-count').textContent = candidates.length;

    const list = document.getElementById('candidate-list');
    list.innerHTML = candidates.map(c => `
        <label>
            <input type="checkbox" value="${c.maimai_id}" checked>
            <span class="candidate-info">
                <span class="candidate-name">${escapeHtml(c.name)}</span>
                <span class="candidate-title">${escapeHtml(c.title)}</span>
                <span class="candidate-company">${escapeHtml(c.company)}</span>
            </span>
        </label>
    `).join('');
}

function toggleSelectAll(checked) {
    document.querySelectorAll('#candidate-list input[type="checkbox"]').forEach(cb => {
        cb.checked = checked;
    });
}

async function confirmCandidates(cancel = false) {
    if (!pipelineTaskId) return;

    let maimai_ids = [];
    if (!cancel) {
        document.querySelectorAll('#candidate-list input[type="checkbox"]:checked').forEach(cb => {
            maimai_ids.push(cb.value);
        });

        if (!maimai_ids.length) {
            return alert('Please select at least one candidate');
        }
    }

    try {
        await fetch(`/api/pipeline/${pipelineTaskId}/confirm`, {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({maimai_ids}),
        });

        document.getElementById('pipeline-confirm').hidden = true;
        if (!cancel) {
            document.getElementById('pipeline-progress').hidden = false;
            document.getElementById('pipeline-status-text').textContent = 'Sending messages...';
        }
    } catch (e) {
        alert('Confirm failed: ' + e.message);
    }
}

// --- Search-only results ---

function showSearchResults(candidates) {
    document.getElementById('search-results').hidden = false;
    document.getElementById('result-count').textContent = candidates.length;
    const tbody = document.getElementById('results-body');
    tbody.innerHTML = candidates.map((c, i) => `
        <tr>
            <td>${i + 1}</td>
            <td>${escapeHtml(c.name)}</td>
            <td>${escapeHtml(c.title)}</td>
            <td>${escapeHtml(c.company)}</td>
            <td>${escapeHtml(c.location || '')}</td>
        </tr>
    `).join('');
}

async function exportResults() {
    const res = await fetch('/api/export', {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({format: 'xlsx'}),
    });
    const blob = await res.blob();
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'candidates.xlsx';
    a.click();
    URL.revokeObjectURL(url);
}

// --- Pipeline results ---

function showPipelineResults(result) {
    document.getElementById('pipeline-progress').hidden = true;
    document.getElementById('pipeline-confirm').hidden = true;
    document.getElementById('pipeline-results').hidden = false;

    const summary = document.getElementById('results-summary');

    if (!result || result.error) {
        summary.innerHTML = `<p>Error: ${result ? result.error : 'Unknown'}</p>`;
        return;
    }

    if (result.dry_run) {
        summary.innerHTML = `
            <p>Dry run complete. Found <strong>${result.total}</strong> candidates.</p>
            <p>No messages were sent.</p>
        `;
        return;
    }

    if (result.message) {
        summary.innerHTML = `<p>${escapeHtml(result.message)}</p>`;
        return;
    }

    summary.innerHTML = `
        <div class="stat-grid">
            <div class="stat">
                <div class="value">${result.total || 0}</div>
                <div class="label">Total</div>
            </div>
            <div class="stat" style="color: #155724">
                <div class="value">${result.sent || 0}</div>
                <div class="label">Sent</div>
            </div>
            <div class="stat" style="color: #721c24">
                <div class="value">${result.failed || 0}</div>
                <div class="label">Failed</div>
            </div>
            <div class="stat" style="color: #856404">
                <div class="value">${result.skipped || 0}</div>
                <div class="label">Skipped</div>
            </div>
            <div class="stat" style="color: #856404">
                <div class="value">${result.rate_limited || 0}</div>
                <div class="label">Rate Limited</div>
            </div>
        </div>
    `;
}

{% extends "base.html" %}

{% block title %}Pipeline - Maimai Assistant{% endblock %}

{% block content %}
<!-- Status bar -->
<div id="status-bar">
    <div class="status-item">
        <span class="dot" id="browser-dot"></span>
        <span>Browser: <strong id="browser-status">--</strong></span>
    </div>
    <div class="status-item">
        <span class="dot" id="login-dot"></span>
        <span>Login: <strong id="login-status">--</strong></span>
    </div>
    <div class="status-item">
        Queue: <strong id="queue-size">0</strong>
    </div>
</div>

<!-- Unified form -->
<form id="pipeline-form">
    <div class="grid">
        <label>
            Keywords (one per line)
            <textarea name="keywords" rows="3" placeholder="e.g. 前端工程师" required></textarea>
        </label>
        <label>
            Company filter (one per line, optional)
            <textarea name="company" rows="3" placeholder="e.g. 字节跳动"></textarea>
        </label>
    </div>
    <div class="grid">
        <label>
            Location (optional)
            <input type="text" name="location" placeholder="e.g. 北京">
        </label>
        <label>
            Template
            <select name="template" id="template-select">
                <option value="">-- Search only --</option>
            </select>
        </label>
        <label>
            Pages
            <input type="number" name="pages" value="1" min="1" max="50">
        </label>
    </div>
    <div id="template-vars"></div>
    <fieldset id="messaging-options" class="hidden">
        <label>
            <input type="checkbox" name="auto_send">
            Auto-send (skip candidate confirmation)
        </label>
    </fieldset>
    <button type="submit" id="submit-btn">Search</button>
</form>

<!-- Progress section -->
<div id="pipeline-progress" hidden>
    <article>
        <header>
            <span id="pipeline-status-text">Queued...</span>
            <span id="pipeline-task-id" class="badge" style="float:right"></span>
        </header>
        <progress id="pipeline-progress-bar" value="0" max="100"></progress>
        <p id="pipeline-detail"></p>
        <div id="pipeline-log"></div>
    </article>
</div>

<!-- Confirmation section (manual mode) -->
<div id="pipeline-confirm" hidden>
    <article>
        <header>Select Candidates to Message</header>
        <p>
            <label>
                <input type="checkbox" id="select-all" onchange="toggleSelectAll(this.checked)">
                Select All (<span id="confirm-count">0</span> candidates)
            </label>
        </p>
        <div id="candidate-list"></div>
        <footer>
            <button onclick="confirmCandidates()" class="primary">Confirm & Send</button>
            <button onclick="confirmCandidates(true)" class="secondary outline">Cancel</button>
        </footer>
    </article>
</div>

<!-- Search results (search-only mode) -->
<div id="search-results" hidden>
    <h3>Results (<span id="result-count">0</span> candidates)</h3>
    <table>
        <thead>
            <tr>
                <th>#</th>
                <th>Name</th>
                <th>Title</th>
                <th>Company</th>
                <th>Location</th>
            </tr>
        </thead>
        <tbody id="results-body"></tbody>
    </table>
    <button id="export-btn" class="outline" onclick="exportResults()">Export to Excel</button>
</div>

<!-- Pipeline results -->
<div id="pipeline-results" hidden>
    <article>
        <header>Pipeline Complete</header>
        <div id="results-summary"></div>
    </article>
</div>
{% endblock %}

{% block scripts %}
<script src="/static/js/pipeline.js"></script>
<script>
// --- Status bar auto-refresh ---
async function refreshStatus() {
    try {
        const [authRes, statusRes] = await Promise.all([
            fetch('/api/auth/status'),
            fetch('/api/status'),
        ]);
        const auth = await authRes.json();
        const status = await statusRes.json();

        const bDot = document.getElementById('browser-dot');
        const lDot = document.getElementById('login-dot');
        document.getElementById('browser-status').textContent = auth.browser_connected ? 'Connected' : 'Disconnected';
        bDot.dataset.ok = auth.browser_connected;
        document.getElementById('login-status').textContent = auth.logged_in ? 'OK' : 'No';
        lDot.dataset.ok = auth.logged_in;
        document.getElementById('queue-size').textContent = status.queue.queue_size;

        // Update connection badge in nav
        const badge = document.getElementById('connection-badge');
        if (auth.browser_connected && auth.logged_in) {
            badge.textContent = 'Online';
            badge.dataset.status = 'ok';
        } else if (auth.browser_connected) {
            badge.textContent = 'Not Logged In';
            badge.dataset.status = 'warn';
        } else {
            badge.textContent = 'Offline';
            badge.dataset.status = 'error';
        }
    } catch (e) {
        console.error('Status refresh failed:', e);
    }
}
refreshStatus();
setInterval(refreshStatus, 10000);

// --- Template loading & mode switching ---
(async () => {
    try {
        const res = await fetch('/api/templates');
        const templates = await res.json();
        const select = document.getElementById('template-select');
        // Append template options after the "Search only" default
        select.innerHTML = '<option value="">-- Search only --</option>' +
            templates.map(t =>
                `<option value="${t.name}">${t.name} — ${t.description || 'No description'}</option>`
            ).join('');

        function onTemplateChange() {
            const tpl = templates.find(t => t.name === select.value);
            const msgOpts = document.getElementById('messaging-options');
            const submitBtn = document.getElementById('submit-btn');
            const varsDiv = document.getElementById('template-vars');

            if (select.value) {
                // Pipeline mode
                msgOpts.classList.remove('hidden');
                submitBtn.textContent = 'Start Pipeline';
                if (tpl && tpl.variables.length) {
                    const autoVars = ['name', 'company', 'position'];
                    const manualVars = tpl.variables.filter(v => !autoVars.includes(v));
                    if (manualVars.length) {
                        varsDiv.innerHTML = '<fieldset><legend>Template Variables</legend>' +
                            manualVars.map(v =>
                                `<label>${v}<input type="text" name="var_${v}" placeholder="${v}"></label>`
                            ).join('') + '</fieldset>';
                    } else {
                        varsDiv.innerHTML = '<small>Variables (name, company, position) will be auto-filled per candidate.</small>';
                    }
                } else {
                    varsDiv.innerHTML = '';
                }
            } else {
                // Search-only mode
                msgOpts.classList.add('hidden');
                submitBtn.textContent = 'Search';
                varsDiv.innerHTML = '';
            }
        }

        select.addEventListener('change', onTemplateChange);
        onTemplateChange(); // init
    } catch (e) {
        console.error('Failed to load templates:', e);
    }
})();
</script>
{% endblock %}

