 59→{% block scripts %}
 60→<script>
 61→// --- Tab switching ---
 62→document.querySelectorAll('.tabs .tab').forEach(btn => {
 63→    btn.addEventListener('click', () => {
 64→        document.querySelectorAll('.tabs .tab').forEach(t => t.classList.remove('active'));
 65→        document.querySelectorAll('.tab-content').forEach(c => c.classList.remove('active'));
 66→        btn.classList.add('active');
 67→        document.getElementById('tab-' + btn.dataset.tab).classList.add('active');
 68→    });
 69→});
 70→
 71→// --- Candidates ---
 72→let candidatePage = 1;
 73→const candidatePageSize = 20;
 74→
 75→async function loadCandidates(page = 1) {
 76→    candidatePage = page;
 77→    const search = document.getElementById('candidate-search').value.trim();
 78→    const params = new URLSearchParams({page, page_size: candidatePageSize});
 79→    if (search) params.append('search', search);
 80→
 81→    try {
 82→        const res = await fetch(`/api/candidates?${params}`);
 83→        const data = await res.json();
 84→        const tbody = document.getElementById('candidates-body');
 85→
 86→        if (!data.items.length) {
 87→            tbody.innerHTML = '<tr><td colspan="7">No candidates found</td></tr>';
 88→            document.getElementById('candidates-pagination').innerHTML = '';
 89→            return;
 90→        }
 91→
 92→        tbody.innerHTML = data.items.map((c, i) => `
 93→            <tr>
 94→                <td>${(page - 1) * candidatePageSize + i + 1}</td>
 95→                <td>${escapeHtml(c.name || '--')}</td>
 96→                <td>${escapeHtml(c.title || '--')}</td>
 97→                <td>${escapeHtml(c.company || '--')}</td>
 98→                <td>${escapeHtml(c.location || '--')}</td>
 99→                <td>${c.message_count}</td>
100→                <td>${c.first_seen ? new Date(c.first_seen).toLocaleDateString() : '--'}</td>
101→            </tr>
102→        `).join('');
103→
104→        const pag = document.getElementById('candidates-pagination');
105→        let html = '';
106→        if (page > 1) html += `<button class="outline" onclick="loadCandidates(${page-1})">Previous</button> `;
107→        html += `<span>Page ${page} / ${data.total_pages} (${data.total} total)</span> `;
108→        if (page < data.total_pages) html += `<button class="outline" onclick="loadCandidates(${page+1})">Next</button>`;
109→        pag.innerHTML = html;
110→    } catch (e) {
111→        console.error('Failed to load candidates:', e);
112→    }
113→}
114→
115→let candidateDebounce;
116→function debouncedLoadCandidates() {
117→    clearTimeout(candidateDebounce);
118→    candidateDebounce = setTimeout(() => loadCandidates(1), 300);
119→}
120→
121→async function exportCandidates() {
122→    const search = document.getElementById('candidate-search').value.trim();
123→    const res = await fetch('/api/export', {
124→        method: 'POST',
125→        headers: {'Content-Type': 'application/json'},
126→        body: JSON.stringify({format: 'xlsx', search_keyword: search || null}),
127→    });
128→    const blob = await res.blob();
129→    const url = URL.createObjectURL(blob);
130→    const a = document.createElement('a');
131→    a.href = url;
132→    a.download = 'candidates.xlsx';
133→    a.click();
134→    URL.revokeObjectURL(url);
135→}
136→
137→// --- Messages ---
138→let msgPage = 1;
139→const msgPageSize = 20;
140→
141→async function loadMessages(page = 1) {
142→    msgPage = page;
143→    try {
144→        const msgRes = await fetch(`/api/messages?page=${page}&page_size=${msgPageSize}`);
145→        const tbody = document.getElementById('messages-body');
146→
147→        if (msgRes.ok) {
148→            const msgData = await msgRes.json();
149→            if (!msgData.items || !msgData.items.length) {
150→                tbody.innerHTML = '<tr><td colspan="6">No messages yet</td></tr>';
151→                document.getElementById('msg-pagination').innerHTML = '';
152→                return;
153→            }
154→            tbody.innerHTML = msgData.items.map((m, i) => `
155→                <tr>
156→                    <td>${(page-1) * msgPageSize + i + 1}</td>
157→                    <td>${escapeHtml(m.candidate_name || m.candidate_maimai_id)}</td>
158→                    <td>${escapeHtml(m.template_name || '--')}</td>
159→                    <td><span class="badge" data-status="${m.status}">${m.status}</span></td>
160→                    <td title="${escapeHtml(m.content)}">${escapeHtml(m.content.substring(0, 60))}${m.content.length > 60 ? '...' : ''}</td>
161→                    <td>${m.sent_at ? new Date(m.sent_at).toLocaleString() : '--'}</td>
162→                </tr>
163→            `).join('');
164→
165→            const pag = document.getElementById('msg-pagination');
166→            let html = '';
167→            if (page > 1) html += `<button class="outline" onclick="loadMessages(${page-1})">Previous</button> `;
168→            html += `<span>Page ${page} / ${msgData.total_pages} (${msgData.total} total)</span> `;
169→            if (page < msgData.total_pages) html += `<button class="outline" onclick="loadMessages(${page+1})">Next</button>`;
170→            pag.innerHTML = html;
171→        } else {
172→            tbody.innerHTML = '<tr><td colspan="6">Messages API not available</td></tr>';
173→        }
174→    } catch (e) {
175→        console.error('Failed to load messages:', e);
176→        document.getElementById('messages-body').innerHTML = '<tr><td colspan="6">Error loading messages</td></tr>';
177→    }
178→}
179→
180→// Init
181→loadCandidates();
182→loadMessages();
183→</script>
184→{% endblock %}
