161→
162→    switch (msg.event) {
163→        case 'search_progress':
164→            statusEl.textContent = `Searching: ${msg.keyword} (${msg.keyword_index}/${msg.total_keywords})`;
165→            appendLog(`Searching keyword ${msg.keyword_index}/${msg.total_keywords}: "${msg.keyword}"`);
166→            break;
167→
168→        case 'search_keyword_done':
169→            detailEl.textContent = `Found ${msg.found} candidates for "${msg.keyword}" (${msg.total_so_far} total)`;
170→            appendLog(`"${msg.keyword}" — found ${msg.found} (total: ${msg.total_so_far})`, 'ok');
171→            break;
172→
173→        case 'search_complete':
174→            statusEl.textContent = 'Search complete';
175→            detailEl.textContent = `${msg.candidates.length} candidates found`;
176→            appendLog(`Search phase done — ${msg.candidates.length} candidates`, 'ok');
177→            break;
178→
179→        case 'awaiting_confirmation':
180→            statusEl.textContent = 'Awaiting your confirmation';
181→            appendLog(`Waiting for confirmation — ${msg.candidates.length} candidates to review`, 'warn');
182→            document.getElementById('pipeline-progress').hidden = true;
183→            showConfirmation(msg.candidates);
