188→            progressBar.max = msg.total;
189→            progressBar.value = 0;
190→            document.getElementById('pipeline-progress').hidden = false;
191→            document.getElementById('pipeline-confirm').hidden = true;
192→            appendLog(`Sending messages to ${msg.total} candidates...`);
193→            break;
194→
195→        case 'send_progress':
196→            statusEl.textContent = `Sending: ${msg.current} (${msg.sent}/${msg.total})`;
197→            progressBar.value = msg.sent + msg.failed;
198→            progressBar.max = msg.total;
